css:
/* 모든 면을 사각으로, 진행바·룰 두껍게 */
.slide li::before { border-radius: 0; width: 0.55em; height: 0.55em; }
.slide[data-layout="SECTION"] .rule { height: 12px; border-radius: 0; }
.slide code { border-radius: 0; border-width: 2px; }
.slide mark { border-radius: 0; }
.progress-bar { background: var(--accent); height: 8px; }
.progress-track { height: 8px; }
/* 통계 카드: 거대 숫자 + 하드 섀도, 강조 모서리는 좌측 두껍게 */
.stat { border-top: none; border-left: 10px solid var(--tone, var(--accent)); }
.stat-value { font-family: var(--font-display); font-size: 100px; }
.compare-col { border-top: none; border-left: 10px solid var(--tone, var(--accent)); }
/* 표: 두꺼운 검정 보더, 그림자 하드 */
.slide table { border: 3px solid var(--ink); border-radius: 0; }
.slide thead th { background: var(--ink); }
.slide tbody th, .slide tbody td { border-top: 2px solid var(--ink); }
/* 콜아웃: 사각 + 하드 섀도 */
.callout { border: 3px solid var(--tone, var(--info)); border-left: 10px solid var(--tone, var(--info)); border-radius: 0; box-shadow: 8px 8px 0 var(--tone, var(--info)); }
/* COVER: 거대 장식 숫자/마크 느낌 — eyebrow 를 검정 pill 로 */
.slide .eyebrow { display: inline-block; background: var(--ink); color: #fff; padding: 8px 16px; }
.slide[data-layout="CLOSING"] .eyebrow { background: var(--accent); }
